  ('social-worker-moex-05732', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '面對倫理難題要在時限內做出審慎評估與最佳抉擇是社工人員很大的挑戰，不同的倫理決策模式各有其 不同的特點。依美國社會工作倫理守則起草人喬瑟夫（Joseph）的倫理決策模式，其中第一個步驟是：', '["從實務環境或機構中分析存在的難題或困境", "找出所有可能被影響到的個人、團體、組織", "找出各種可能行動並評估每種行動的利弊得失", "明確指出那些義務是社工一定要執行的義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
